const { ipcRenderer } = require('electron');

// DOM 元素
const urlInput = document.getElementById('urlInput');
const pasteBtn = document.getElementById('pasteBtn');
const platformIndicator = document.getElementById('platformIndicator');
const progressFill = document.getElementById('progressFill');
const statusText = document.getElementById('statusText');
const extractBtn = document.getElementById('extractBtn');
const downloadBtn = document.getElementById('downloadBtn');
const infoModal = document.getElementById('infoModal');
const modalBody = document.getElementById('modalBody');
const closeModal = document.getElementById('closeModal');

// 状态变量
let currentMode = 'merge';
let isProcessing = false;

// 检测平台
function detectPlatform(url) {
    url = url.toLowerCase();
    if (url.includes('youtube.com') || url.includes('youtu.be')) {
        return 'youtube';
    }
    if (url.includes('douyin.com') || url.includes('iesdouyin.com')) {
        return 'douyin';
    }
    if (url.includes('tiktok.com')) {
        return 'tiktok';
    }
    if (url.includes('bilibili.com')) {
        return 'bilibili';
    }
    return 'unknown';
}

// URL 输入变化检测
urlInput.addEventListener('input', () => {
    const platform = detectPlatform(urlInput.value);
    if (platform === 'youtube') {
        platformIndicator.textContent = '📡 检测到: YouTube';
        platformIndicator.style.color = '#ff0000';
    } else if (platform === 'douyin') {
        platformIndicator.textContent = '🎵 检测到: 抖音';
        platformIndicator.style.color = '#00d1ff';
    } else if (platform === 'tiktok') {
        platformIndicator.textContent = '🎵 检测到: TikTok';
        platformIndicator.style.color = '#00f2ea';
    } else if (platform === 'bilibili') {
        platformIndicator.textContent = '📺 检测到: Bilibili';
        platformIndicator.style.color = '#fb7299';
    } else if (urlInput.value && !urlInput.value.includes('粘贴')) {
        platformIndicator.textContent = '⚠️ 不支持的链接';
        platformIndicator.style.color = '#ff6600';
    } else {
        platformIndicator.textContent = '📡 等待输入...';
        platformIndicator.style.color = 'rgba(255, 255, 255, 0.5)';
    }
});

// 从粘贴文本中提取 URL（处理分享文本如 "【标题】 https://xxx"）
function extractUrl(text) {
    const match = text.match(/https?:\/\/[^\s"'<>]+/);
    return match ? match[0] : text.trim();
}

// 粘贴按钮
pasteBtn.addEventListener('click', async () => {
    try {
        const text = await navigator.clipboard.readText();
        urlInput.value = extractUrl(text);
        urlInput.dispatchEvent(new Event('input'));
        statusText.textContent = '已粘贴链接';
    } catch (err) {
        statusText.textContent = '剪贴板为空';
    }
});

// 模式选择按钮
document.querySelectorAll('.mode-btn').forEach(btn => {
    btn.addEventListener('click', () => {
        document.querySelectorAll('.mode-btn').forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
        currentMode = btn.dataset.mode;
    });
});

// 平台名称映射
const platformNames = {
    youtube: 'YouTube',
    douyin: '抖音',
    tiktok: 'TikTok',
    bilibili: 'Bilibili'
};

// 提取视频信息
extractBtn.addEventListener('click', async () => {
    if (isProcessing) return;

    const url = urlInput.value.trim();
    if (!url || url.includes('粘贴')) {
        alert('请输入有效的视频链接！');
        return;
    }

    const platform = detectPlatform(url);
    if (platform === 'unknown') {
        alert('请输入有效的视频链接！\n\n支持的平台：\n• YouTube\n• 抖音\n• TikTok\n• Bilibili');
        return;
    }

    isProcessing = true;
    extractBtn.disabled = true;
    statusText.textContent = `正在解析 ${platformNames[platform]} 视频信息...`;

    try {
        const result = await ipcRenderer.invoke('extract-info', url);
        if (result.success) {
            modalBody.textContent = result.info;
            infoModal.classList.add('show');
            statusText.textContent = '信息获取成功！';
        } else {
            statusText.textContent = '获取信息失败';
            alert('获取视频信息失败！\n\n' + result.error);
        }
    } catch (err) {
        statusText.textContent = '发生错误';
        alert('获取信息出错：' + err.message);
    } finally {
        isProcessing = false;
        extractBtn.disabled = false;
    }
});

// 开始下载
downloadBtn.addEventListener('click', async () => {
    if (isProcessing) return;

    const url = urlInput.value.trim();
    if (!url || url.includes('粘贴')) {
        alert('请输入有效的视频链接！');
        return;
    }

    const platform = detectPlatform(url);
    if (platform === 'unknown') {
        alert('请输入有效的视频链接！');
        return;
    }

    isProcessing = true;
    downloadBtn.disabled = true;
    progressFill.style.width = '0%';

    statusText.textContent = `正在解析 ${platformNames[platform]} 视频...`;

    try {
        const result = await ipcRenderer.invoke('start-download', url, currentMode);
        if (result.success) {
            progressFill.style.width = '100%';
            statusText.textContent = '下载完成！';
            alert('视频已下载到桌面！');
        } else {
            progressFill.style.width = '0%';
            statusText.textContent = '下载失败';
            alert('下载失败！\n\n' + result.error);
        }
    } catch (err) {
        progressFill.style.width = '0%';
        statusText.textContent = '发生错误';
        alert('下载出错：' + err.message);
    } finally {
        isProcessing = false;
        downloadBtn.disabled = false;
    }
});

// 监听下载进度
ipcRenderer.on('download-progress', (event, progress) => {
    progressFill.style.width = progress.percent + '%';
    statusText.textContent = `下载中... ${progress.percent.toFixed(0)}%`;
});

// 关闭弹窗
closeModal.addEventListener('click', () => {
    infoModal.classList.remove('show');
});

infoModal.addEventListener('click', (e) => {
    if (e.target === infoModal) {
        infoModal.classList.remove('show');
    }
});

// 清除占位符
urlInput.addEventListener('focus', () => {
    if (urlInput.value.includes('粘贴')) {
        urlInput.value = '';
    }
});

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Microsoft YaHei UI', -apple-system, BlinkMacSystemFont, sans-serif;
    overflow-y: auto;
    min-height: 100vh;
    background: #0a0a1a;
}

/* 极光渐变背景 */
.aurora-bg {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    z-index: -1;
    background: linear-gradient(135deg, #0a0a1a 0%, #1a0a2e 50%, #0a1a2e 100%);
}

.aurora-blob {
    position: absolute;
    border-radius: 50%;
    filter: blur(80px);
    opacity: 0.6;
    animation: float 20s ease-in-out infinite;
}

.blob-1 {
    width: 500px;
    height: 500px;
    background: linear-gradient(45deg, #ff6b9d, #c04868);
    top: -200px;
    left: -100px;
    animation-delay: 0s;
}

.blob-2 {
    width: 400px;
    height: 400px;
    background: linear-gradient(45deg, #8a2be2, #5d26c1);
    top: 50%;
    right: -150px;
    animation-delay: -5s;
}

.blob-3 {
    width: 450px;
    height: 450px;
    background: linear-gradient(45deg, #00c8ff, #06b6d4);
    bottom: -150px;
    left: 30%;
    animation-delay: -10s;
}

.blob-4 {
    width: 350px;
    height: 350px;
    background: linear-gradient(45deg, #ff6b9d, #8a2be2);
    top: 40%;
    left: 40%;
    animation-delay: -15s;
}

@keyframes float {
    0%, 100% {
        transform: translate(0, 0) scale(1);
    }
    25% {
        transform: translate(50px, -50px) scale(1.1);
    }
    50% {
        transform: translate(-30px, 30px) scale(0.9);
    }
    75% {
        transform: translate(-50px, -30px) scale(1.05);
    }
}

/* 主容器 */
.container {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 25px 20px;
    min-height: 100vh;
    overflow-y: auto;
}

/* Logo 区域 */
.header {
    text-align: center;
    margin-bottom: 25px;
}

.logo-container {
    display: flex;
    justify-content: center;
    gap: 20px;
    margin-bottom: 15px;
}

.logo {
    width: 70px;
    height: 70px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
}

.youtube-logo {
    background: linear-gradient(135deg, #ff0000, #cc0000);
}

.douyin-logo {
    background: linear-gradient(135deg, #00c8ff, #0099cc);
}

.logo svg {
    width: 35px;
    height: 35px;
}

.title {
    font-size: 32px;
    font-weight: bold;
    color: #ffffff;
    margin-bottom: 8px;
    text-shadow: 0 2px 20px rgba(255, 107, 157, 0.5);
}

.subtitle {
    font-size: 14px;
    color: #ff6b9d;
}

/* 玻璃拟态卡片 */
.glass-card {
    background: rgba(42, 26, 58, 0.6);
    backdrop-filter: blur(20px);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 20px;
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
}

.main-card {
    width: 100%;
    max-width: 520px;
    padding: 25px;
    margin-bottom: 20px;
    flex-shrink: 0;
}

/* 标签 */
.label {
    display: block;
    font-size: 13px;
    font-weight: bold;
    color: #ff6b9d;
    margin-bottom: 10px;
}

/* 输入区域 */
.input-section {
    margin-bottom: 20px;
}

.input-wrapper {
    display: flex;
    gap: 10px;
}

.url-input {
    flex: 1;
    padding: 14px 18px;
    font-size: 14px;
    background: rgba(26, 10, 42, 0.8);
    border: 1px solid rgba(255, 107, 157, 0.3);
    border-radius: 12px;
    color: #ffffff;
    outline: none;
    transition: all 0.3s ease;
}

.url-input:focus {
    border-color: #ff6b9d;
    box-shadow: 0 0 20px rgba(255, 107, 157, 0.3);
}

.url-input::placeholder {
    color: rgba(255, 255, 255, 0.4);
}

.paste-btn {
    width: 50px;
    height: 50px;
    font-size: 20px;
    background: linear-gradient(135deg, #8a2be2, #5d26c1);
    border: none;
    border-radius: 12px;
    cursor: pointer;
    transition: all 0.3s ease;
}

.paste-btn:hover {
    transform: scale(1.05);
    box-shadow: 0 5px 20px rgba(138, 43, 226, 0.4);
}

.platform-indicator {
    margin-top: 10px;
    font-size: 12px;
    color: rgba(255, 255, 255, 0.5);
}

/* 模式选择 */
.mode-section {
    margin-bottom: 20px;
}

.mode-buttons {
    display: flex;
    gap: 10px;
}

.mode-btn {
    flex: 1;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 8px;
    padding: 15px 10px;
    background: rgba(255, 255, 255, 0.05);
    border: 1px solid rgba(255, 255, 255, 0.1);
    border-radius: 12px;
    cursor: pointer;
    transition: all 0.3s ease;
}

.mode-btn:hover {
    background: rgba(255, 255, 255, 0.1);
}

.mode-btn.active {
    background: linear-gradient(135deg, rgba(255, 107, 157, 0.3), rgba(138, 43, 226, 0.3));
    border-color: #ff6b9d;
}

.mode-icon {
    font-size: 24px;
}

.mode-text {
    font-size: 12px;
    color: #ffffff;
}

/* 进度条 */
.progress-section {
    margin-bottom: 20px;
}

.progress-bar {
    height: 10px;
    background: rgba(26, 10, 42, 0.8);
    border-radius: 10px;
    overflow: hidden;
    margin-bottom: 10px;
}

.progress-fill {
    height: 100%;
    width: 0%;
    background: linear-gradient(90deg, #ff6b9d, #8a2be2, #00c8ff);
    border-radius: 10px;
    transition: width 0.3s ease;
}

.status-text {
    font-size: 12px;
    color: rgba(255, 255, 255, 0.6);
    text-align: center;
}

/* 操作按钮 */
.action-buttons {
    display: flex;
    flex-direction: column;
    gap: 12px;
    margin-bottom: 15px;
}

.btn {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 12px;
    padding: 18px;
    font-size: 16px;
    font-weight: bold;
    border: none;
    border-radius: 14px;
    cursor: pointer;
    transition: all 0.3s ease;
}

.btn-icon {
    font-size: 20px;
}

.btn-text {
    color: #ffffff;
}

.btn-primary {
    background: linear-gradient(135deg, #ff3366, #ff6b9d);
    box-shadow: 0 4px 20px rgba(255, 51, 102, 0.4);
}

.btn-primary:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 30px rgba(255, 51, 102, 0.6);
}

.btn-info {
    background: linear-gradient(135deg, #00aacc, #06b6d4);
    box-shadow: 0 4px 20px rgba(0, 170, 204, 0.4);
}

.btn-info:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 30px rgba(0, 170, 204, 0.6);
}

.btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    transform: none !important;
}

/* 信息框 */
.info-box {
    padding: 15px;
    background: rgba(26, 10, 42, 0.6);
    border-radius: 12px;
}

.info-box p {
    font-size: 12px;
    color: rgba(255, 255, 255, 0.5);
    line-height: 1.8;
    margin: 0;
}

/* 底部信息 */
.footer {
    font-size: 12px;
    color: rgba(255, 255, 255, 0.4);
    text-align: center;
}

/* 弹窗 */
.modal {
    display: none;
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.7);
    backdrop-filter: blur(5px);
    z-index: 1000;
    align-items: center;
    justify-content: center;
}

.modal.show {
    display: flex;
}

.modal-content {
    width: 90%;
    max-width: 500px;
    max-height: 80vh;
    overflow: auto;
}

.modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 20px;
}

.modal-header h2 {
    font-size: 20px;
    color: #ff6b9d;
}

.close-btn {
    width: 35px;
    height: 35px;
    font-size: 18px;
    background: rgba(255, 255, 255, 0.1);
    border: none;
    border-radius: 50%;
    color: #ffffff;
    cursor: pointer;
    transition: all 0.3s ease;
}

.close-btn:hover {
    background: rgba(255, 107, 157, 0.5);
}

.modal-body {
    color: #ffffff;
    line-height: 1.8;
    font-size: 14px;
    white-space: pre-wrap;
}

/* 滚动条 */
::-webkit-scrollbar {
    width: 8px;
}

::-webkit-scrollbar-track {
    background: rgba(255, 255, 255, 0.05);
    border-radius: 10px;
}

::-webkit-scrollbar-thumb {
    background: rgba(255, 107, 157, 0.5);
    border-radius: 10px;
}

::-webkit-scrollbar-thumb:hover {
    background: rgba(255, 107, 157, 0.7);
}

const { app, BrowserWindow, ipcMain, session } = require('electron');
const path = require('path');
const { spawn } = require('child_process');
const os = require('os');
const fs = require('fs');
const https = require('https');
const http = require('http');

let mainWindow;
const COOKIES_FILE = app.isPackaged
    ? path.join(process.resourcesPath, 'cookies.txt')
    : path.join(__dirname, 'cookies.txt');

// 内置工具路径（打包后在 resources/bin，开发时在 __dirname/bin）
const BIN_DIR = app.isPackaged
    ? path.join(process.resourcesPath, 'bin')
    : path.join(__dirname, 'bin');
const YTDLP = path.join(BIN_DIR, 'yt-dlp.exe');
const FFMPEG = path.join(BIN_DIR, 'ffmpeg.exe');

function getYtdlp() {
    return fs.existsSync(YTDLP) ? YTDLP : 'yt-dlp';
}

// 需要预获取 cookies 的平台
const COOKIE_DOMAINS = {
    douyin: 'https://www.douyin.com/',
    bilibili: 'https://www.bilibili.com/'
};

/**
 * 用隐藏窗口访问目标网站，获取真实浏览器 cookies
 */
async function fetchCookies(url) {
    return new Promise((resolve) => {
        const win = new BrowserWindow({
            width: 800, height: 600,
            show: false,
            webPreferences: { nodeIntegration: false, contextIsolation: true }
        });

        const timeout = setTimeout(() => {
            win.destroy();
            resolve();
        }, 15000);

        win.webContents.on('did-finish-load', () => {
            setTimeout(() => {
                clearTimeout(timeout);
                win.destroy();
                resolve();
            }, 5000);
        });

        win.loadURL(url).catch(() => {
            clearTimeout(timeout);
            win.destroy();
            resolve();
        });
    });
}

/**
 * 将 Electron session cookies 导出为 Netscape 格式文件
 */
async function exportCookies() {
    const cookies = await session.defaultSession.cookies.get({});
    let content = '# Netscape HTTP Cookie File\n';
    for (const c of cookies) {
        const domain = c.domain.startsWith('.') ? c.domain : '.' + c.domain;
        const flag = 'TRUE';
        const securePath = c.path || '/';
        const secure = c.secure ? 'TRUE' : 'FALSE';
        const expiry = c.expirationDate ? Math.floor(c.expirationDate) : '0';
        content += `${domain}\t${flag}\t${securePath}\t${secure}\t${expiry}\t${c.name}\t${c.value}\n`;
    }
    fs.writeFileSync(COOKIES_FILE, content, 'utf-8');
}

/**
 * 预热：获取需要 cookies 的平台
 */
async function warmupCookies() {
    for (const [, url] of Object.entries(COOKIE_DOMAINS)) {
        await fetchCookies(url);
    }
    await exportCookies();
    console.log('Cookies 预热完成');
}

function createWindow() {
    mainWindow = new BrowserWindow({
        width: 600,
        height: 700,
        minWidth: 500,
        minHeight: 600,
        frame: true,
        titleBarStyle: 'default',
        backgroundColor: '#0a0a1a',
        webPreferences: {
            nodeIntegration: true,
            contextIsolation: false
        }
    });
    mainWindow.loadFile('index.html');
}

app.whenReady().then(() => {
    createWindow();
    // 延迟预热 cookies，不阻塞启动
    mainWindow.webContents.once('did-finish-load', () => {
        setTimeout(() => warmupCookies().catch(() => {}), 3000);
    });

    app.on('activate', () => {
        if (BrowserWindow.getAllWindows().length === 0) createWindow();
    });
});

app.on('window-all-closed', () => {
    if (process.platform !== 'darwin') app.quit();
});

function getDesktopPath() {
    return path.join(os.homedir(), 'Desktop');
}

function detectPlatform(url) {
    url = url.toLowerCase();
    if (url.includes('youtube.com') || url.includes('youtu.be')) return 'youtube';
    if (url.includes('douyin.com') || url.includes('iesdouyin.com')) return 'douyin';
    if (url.includes('tiktok.com')) return 'tiktok';
    if (url.includes('bilibili.com')) return 'bilibili';
    return 'unknown';
}

// ============= 抖音：Electron 浏览器内核解析 =============

/**
 * 用隐藏窗口加载抖音视频页面，注入 JS 提取视频数据
 */
async function extractDouyinData(url) {
    return new Promise((resolve, reject) => {
        const win = new BrowserWindow({
            width: 800, height: 600,
            show: false,
            webPreferences: { nodeIntegration: false, contextIsolation: true }
        });

        const timeout = setTimeout(() => {
            win.destroy();
            reject(new Error('抖音页面加载超时'));
        }, 20000);

        win.webContents.on('did-finish-load', () => {
            setTimeout(async () => {
                try {
                    const data = await win.webContents.executeJavaScript(`
                        (function() {
                            try {
                                // 方法1: __UNIVERSAL_DATA_FOR_REHYDRATION__
                                var el = document.getElementById('RENDER_DATA');
                                if (el) {
                                    var decoded = decodeURIComponent(el.textContent);
                                    return { method: 'RENDER_DATA', data: decoded };
                                }

                                // 方法2: RENDER_DATA 不存在时尝试 SSR_HYDRATED_DATA
                                var scripts = document.querySelectorAll('script');
                                for (var i = 0; i < scripts.length; i++) {
                                    var text = scripts[i].textContent || '';
                                    if (text.includes('window._SSR_HYDRATED_DATA')) {
                                        var match = text.match(/window\\._SSR_HYDRATED_DATA\\s*=\\s*(\\{.+?\\})\\s*;?\\s*$/s);
                                        if (match) return { method: 'SSR', data: match[1] };
                                    }
                                }

                                // 方法3: 直接找 video 标签
                                var video = document.querySelector('video source');
                                if (video && video.src) {
                                    return { method: 'video_tag', videoUrl: video.src, title: document.title };
                                }
                                var videoEl = document.querySelector('video');
                                if (videoEl && videoEl.src) {
                                    return { method: 'video_tag', videoUrl: videoEl.src, title: document.title };
                                }

                                return { method: 'none', html: document.title };
                            } catch(e) {
                                return { method: 'error', error: e.message };
                            }
                        })()
                    `);

                    clearTimeout(timeout);
                    win.destroy();
                    resolve(data);
                } catch (err) {
                    clearTimeout(timeout);
                    win.destroy();
                    reject(err);
                }
            }, 3000);
        });

        win.loadURL(url).catch(err => {
            clearTimeout(timeout);
            win.destroy();
            reject(err);
        });
    });
}

/**
 * 从抖音页面数据中解析视频信息
 */
function parseDouyinData(rawData) {
    try {
        if (rawData.method === 'video_tag') {
            return {
                title: rawData.title || '抖音视频',
                videoUrl: rawData.videoUrl,
                desc: rawData.title || ''
            };
        }

        const data = JSON.parse(rawData.data);

        // RENDER_DATA 格式
        if (rawData.method === 'RENDER_DATA') {
            // 遍历所有 key 找视频数据
            for (const key of Object.keys(data)) {
                const section = data[key];
                // 查找 aweme detail
                const detail = section?.awemeDetail || section?.videoInfoRes?.item_list?.[0];
                if (detail) {
                    const video = detail.video || {};
                    const playAddr = video.play_addr || video.playAddr || {};
                    const urlList = playAddr.url_list || [];
                    const videoUrl = urlList[0] || video.download_addr?.url_list?.[0];
                    return {
                        title: detail.desc || '抖音视频',
                        desc: detail.desc || '',
                        author: detail.author?.nickname || '',
                        duration: video.duration ? video.duration / 1000 : 0,
                        videoUrl: videoUrl
                    };
                }
            }
        }

        // SSR 格式
        if (rawData.method === 'SSR') {
            const detail = data?.anyVideo?.videoInfoRes?.item_list?.[0] ||
                          data?.videoDetail?.videoInfo;
            if (detail) {
                const video = detail.video || {};
                const playAddr = video.play_addr || {};
                const urlList = playAddr.url_list || [];
                return {
                    title: detail.desc || '抖音视频',
                    desc: detail.desc || '',
                    author: detail.author?.nickname || '',
                    videoUrl: urlList[0]
                };
            }
        }

        return null;
    } catch (e) {
        console.error('解析抖音数据失败:', e.message);
        return null;
    }
}

async function extractDouyinInfo(url) {
    try {
        const rawData = await extractDouyinData(url);
        const parsed = parseDouyinData(rawData);
        if (parsed) {
            let infoText = `📹 标题：${parsed.title || 'N/A'}`;
            if (parsed.author) infoText += `\n\n👤 作者：${parsed.author}`;
            if (parsed.duration) infoText += `\n⏱️ 时长：${formatDuration(parsed.duration)}`;
            if (parsed.desc) infoText += `\n\n📝 描述：\n${parsed.desc.substring(0, 200)}`;
            return { success: true, info: infoText, _videoUrl: parsed.videoUrl, _title: parsed.title };
        }
        return { success: false, error: '无法解析抖音视频数据' };
    } catch (err) {
        return { success: false, error: err.message };
    }
}

async function downloadDouyinVideo(videoUrl, title) {
    const outputDir = getDesktopPath();
    const safeName = (title || 'douyin_video').replace(/[<>:"/\\|?*]/g, '_').substring(0, 80);
    const filePath = path.join(outputDir, `${safeName}.mp4`);

    return new Promise((resolve) => {
        const urlObj = new URL(videoUrl);
        const client = urlObj.protocol === 'https:' ? https : http;

        const reqOptions = {
            hostname: urlObj.hostname,
            path: urlObj.pathname + urlObj.search,
            method: 'GET',
            headers: {
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
                'Referer': 'https://www.douyin.com/'
            }
        };

        const req = client.request(reqOptions, (res) => {
            // 跟随重定向
            if (res.statusCode === 301 || res.statusCode === 302) {
                const redirectUrl = res.headers.location;
                if (redirectUrl) {
                    downloadDouyinVideo(redirectUrl, title).then(resolve);
                    return;
                }
            }

            if (res.statusCode !== 200) {
                resolve({ success: false, error: `HTTP ${res.statusCode}` });
                return;
            }

            const fileStream = fs.createWriteStream(filePath);
            let downloaded = 0;
            const total = parseInt(res.headers['content-length']) || 0;

            res.on('data', (chunk) => {
                downloaded += chunk.length;
                if (total > 0) {
                    mainWindow.webContents.send('download-progress', {
                        percent: (downloaded / total) * 100
                    });
                }
            });

            res.pipe(fileStream);
            fileStream.on('finish', () => {
                fileStream.close();
                resolve({ success: true, file: filePath });
            });
            fileStream.on('error', (err) => {
                fs.unlink(filePath, () => {});
                resolve({ success: false, error: err.message });
            });
        });

        req.on('error', (err) => resolve({ success: false, error: err.message }));
        req.setTimeout(60000, () => {
            req.destroy();
            resolve({ success: false, error: '下载超时' });
        });
        req.end();
    });
}

// ============= yt-dlp 处理 YouTube / TikTok / Bilibili =============

function baseArgs(platform) {
    const args = [];
    if (fs.existsSync(FFMPEG)) {
        args.push('--ffmpeg-location', BIN_DIR);
    }
    if (platform === 'bilibili' && fs.existsSync(COOKIES_FILE)) {
        args.push('--cookies', COOKIES_FILE);
    }
    return args;
}

async function extractYtdlpInfo(url, platform) {
    return new Promise((resolve) => {
        const args = [...baseArgs(platform), '--dump-json', '--no-playlist', url];
        const proc = spawn(getYtdlp(), args);

        let stdout = '';
        let stderr = '';

        proc.stdout.on('data', (data) => { stdout += data.toString(); });
        proc.stderr.on('data', (data) => { stderr += data.toString(); });

        proc.on('close', (code) => {
            if (code === 0) {
                try {
                    const info = JSON.parse(stdout);
                    const infoText = `📹 标题：${info.title || 'N/A'}

👤 频道：${info.channel || info.uploader || 'N/A'}
⏱️ 时长：${formatDuration(info.duration)}
👁️ 观看：${formatViews(info.view_count)}

📅 上传：${info.upload_date ? info.upload_date.substring(0, 10) : 'N/A'}
🔗 链接：${info.webpage_url || url}

📝 描述：
${info.description ? info.description.substring(0, 200) + (info.description.length > 200 ? '...' : '') : '无描述'}`;
                    resolve({ success: true, info: infoText });
                } catch (e) {
                    resolve({ success: false, error: '解析失败' });
                }
            } else {
                resolve({ success: false, error: stderr || '获取信息失败' });
            }
        });

        proc.on('error', () => {
            resolve({ success: false, error: 'yt-dlp 未安装，请先安装 yt-dlp' });
        });
    });
}

async function downloadYtdlp(url, mode, platform) {
    return new Promise((resolve) => {
        const outputDir = getDesktopPath();
        const outputTemplate = path.join(outputDir, '%(title)s.%(ext)s');
        let args = [...baseArgs(platform), '--no-playlist'];

        if (mode === 'audio') {
            args.push('-f', 'bestaudio', '-x', '--audio-format', 'mp3', '-o', outputTemplate, url);
        } else if (mode === 'video') {
            args.push('-f', 'bestvideo', '-o', outputTemplate, url);
        } else {
            args.push('-f', 'bestvideo+bestaudio/best', '--merge-output-format', 'mp4', '-o', outputTemplate, url);
        }

        const proc = spawn(getYtdlp(), args);
        let stderr = '';
        let streamCount = 0;
        let maxPercent = 0;

        proc.stdout.on('data', (data) => {
            const output = data.toString();
            if (output.includes('Destination:')) {
                streamCount++;
            }
            // 提取最后一个百分比（一次 data 可能包含多个）
            const matches = output.match(/(\d+\.?\d*)%/g);
            if (matches) {
                const lastMatch = matches[matches.length - 1];
                let percent = parseFloat(lastMatch);
                // 双流下载时：第一个流 0-50%，第二个流 50-100%
                if (streamCount >= 2) {
                    percent = 50 + percent / 2;
                } else if (streamCount === 1 && mode !== 'audio' && mode !== 'video') {
                    percent = percent / 2;
                }
                if (percent > maxPercent) {
                    maxPercent = percent;
                    mainWindow.webContents.send('download-progress', { percent: maxPercent });
                }
            }
            if (output.includes('Merging') || output.includes('[Merger]')) {
                maxPercent = 99;
                mainWindow.webContents.send('download-progress', { percent: 99 });
            }
        });

        proc.stderr.on('data', (data) => { stderr += data.toString(); });

        proc.on('close', (code) => {
            resolve(code === 0 ? { success: true } : { success: false, error: stderr || '下载失败' });
        });

        proc.on('error', () => {
            resolve({ success: false, error: 'yt-dlp 未安装，请先安装 yt-dlp' });
        });
    });
}

// ============= IPC 接口 =============

function cleanUrl(url) {
    const match = url.match(/https?:\/\/[^\s"'<>]+/);
    return match ? match[0] : url.trim();
}

ipcMain.handle('extract-info', async (event, url) => {
    url = cleanUrl(url);
    const platform = detectPlatform(url);
    if (platform === 'unknown') return { success: false, error: '不支持的平台 URL' };

    if (platform === 'douyin') {
        return await extractDouyinInfo(url);
    }
    return await extractYtdlpInfo(url, platform);
});

ipcMain.handle('start-download', async (event, url, mode) => {
    url = cleanUrl(url);
    const platform = detectPlatform(url);
    if (platform === 'unknown') return { success: false, error: '不支持的平台 URL' };

    if (platform === 'douyin') {
        // 先提取视频信息获取下载链接
        const info = await extractDouyinInfo(url);
        if (!info.success || !info._videoUrl) {
            return { success: false, error: info.error || '无法获取抖音视频下载链接' };
        }
        return await downloadDouyinVideo(info._videoUrl, info._title);
    }
    return await downloadYtdlp(url, mode, platform);
});

ipcMain.handle('refresh-cookies', async () => {
    try {
        await warmupCookies();
        return { success: true };
    } catch (err) {
        return { success: false, error: err.message };
    }
});

// ============= 工具函数 =============

function formatDuration(seconds) {
    if (!seconds) return 'N/A';
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    const secs = Math.floor(seconds % 60);
    if (hours > 0) {
        return `${hours}:${minutes.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
    }
    return `${minutes}:${secs.toString().padStart(2, '0')}`;
}

function formatViews(count) {
    if (!count) return 'N/A';
    if (count >= 1000000) return `${(count / 1000000).toFixed(1)}M`;
    if (count >= 1000) return `${(count / 1000).toFixed(1)}K`;
    return String(count);
}

