const path = require('path');
const { spawn } = require('child_process');
const os = require('os');
const fs = require('fs');
const https = require('https');
const http = require('http');

let mainWindow;
const COOKIES_FILE = app.isPackaged
    ? path.join(process.resourcesPath, 'cookies.txt')
    : path.join(__dirname, 'cookies.txt');

// 内置工具路径（打包后在 resources/bin，开发时在 __dirname/bin）
const BIN_DIR = app.isPackaged
    ? path.join(process.resourcesPath, 'bin')
    : path.join(__dirname, 'bin');
const YTDLP = path.join(BIN_DIR, 'yt-dlp.exe');
const FFMPEG = path.join(BIN_DIR, 'ffmpeg.exe');

function getYtdlp() {
    return fs.existsSync(YTDLP) ? YTDLP : 'yt-dlp';
}

// 需要预获取 cookies 的平台
const COOKIE_DOMAINS = {
    douyin: 'https://www.douyin.com/',
    bilibili: 'https://www.bilibili.com/'
};

/**
 * 用隐藏窗口访问目标网站，获取真实浏览器 cookies
 */
async function fetchCookies(url) {
    return new Promise((resolve) => {
        const win = new BrowserWindow({
            width: 800, height: 600,
            show: false,
            webPreferences: { nodeIntegration: false, contextIsolation: true }
        });

        const timeout = setTimeout(() => {
            win.destroy();
            resolve();
        }, 15000);

        win.webContents.on('did-finish-load', () => {
            setTimeout(() => {
                clearTimeout(timeout);
                win.destroy();
                resolve();
            }, 5000);
        });

        win.loadURL(url).catch(() => {
            clearTimeout(timeout);
            win.destroy();
            resolve();
        });
    });
}

/**
 * 将 Electron session cookies 导出为 Netscape 格式文件
 */
async function exportCookies() {
    const cookies = await session.defaultSession.cookies.get({});
    let content = '# Netscape HTTP Cookie File\n';
    for (const c of cookies) {
        const domain = c.domain.startsWith('.') ? c.domain : '.' + c.domain;
        const flag = 'TRUE';
        const securePath = c.path || '/';
        const secure = c.secure ? 'TRUE' : 'FALSE';
        const expiry = c.expirationDate ? Math.floor(c.expirationDate) : '0';
        content += `${domain}\t${flag}\t${securePath}\t${secure}\t${expiry}\t${c.name}\t${c.value}\n`;
    }
    fs.writeFileSync(COOKIES_FILE, content, 'utf-8');
}

/**
 * 预热：获取需要 cookies 的平台
 */
async function warmupCookies() {
    for (const [, url] of Object.entries(COOKIE_DOMAINS)) {
        await fetchCookies(url);
    }
    await exportCookies();
    console.log('Cookies 预热完成');
}

function createWindow() {
