152→async function loadVideo(videoPath, subtitlePath) {
153→  playerArea.style.display = 'block';
154→  videoPlayer.src = videoPath;
155→  subtitles = []; currentSubIndex = -1;
156→  subtitleText.textContent = '等待播放...';
157→  aiAnalyzeBtn.style.display = 'none';
158→  aiResult.style.display = 'none';
159→  const subtitleList = document.getElementById('subtitleList');
160→  subtitleList.innerHTML = '';
161→  if (subtitlePath) {
162→    const vtt = await ipcRenderer.invoke('read-subtitle', subtitlePath);
163→    if (vtt) {
164→      subtitles = parseVTT(vtt);
165→      buildSubtitleList();
166→    }
167→  }
168→}
