170→// VTT解析
171→function parseVTT(vtt) {
172→  const result = [];
173→  for (const block of vtt.split(/\n\n+/)) {
174→    const lines = block.trim().split('\n');
175→    for (let i = 0; i < lines.length; i++) {
176→      const m = lines[i].match(/(\d{2}):(\d{2}):(\d{2})\.(\d{3})\s*-->\s*(\d{2}):(\d{2}):(\d{2})\.(\d{3})/);
177→      if (!m) continue;
178→      const start = +m[1]*3600 + +m[2]*60 + +m[3] + +m[4]/1000;
179→      const end = +m[5]*3600 + +m[6]*60 + +m[7] + +m[8]/1000;
180→      const text = lines.slice(i+1).join(' ').replace(/<[^>]+>/g, '').trim();
181→      if (text) result.push({ start, end, text });
182→      break;
183→    }
184→  }
185→  // 去重
186→  return result.filter((s, i, a) => i === 0 || s.text !== a[i-1].text);
187→}
