189→// 字幕同步
190→videoPlayer.addEventListener('timeupdate', () => {
191→  if (!subtitles.length || currentMode !== 'learn') return;
192→  const t = videoPlayer.currentTime;
193→  // 精确匹配当前时间段
194→  let idx = subtitles.findIndex(s => t >= s.start && t <= s.end);
195→  // 间隙时找最近的下一条
196→  if (idx < 0) {
197→    idx = subtitles.findIndex(s => s.start > t);
198→    if (idx < 0) idx = subtitles.length - 1; // 超过最后一条就显示最后一条
199→    // 如果离上一条更近就显示上一条
200→    if (idx > 0 && (t - subtitles[idx-1].end) < (subtitles[idx].start - t)) idx = idx - 1;
201→  }
202→  if (idx !== currentSubIndex) {
203→    currentSubIndex = idx;
204→    currentSentence = subtitles[idx].text;
205→    renderSubtitle(currentSentence);
206→    aiAnalyzeBtn.style.display = 'inline-block';
207→    aiResult.style.display = 'none';
208→    highlightSubtitleList(idx);
