212→function renderSubtitle(text) {
213→  subtitleText.innerHTML = '';
214→  for (const w of text.split(/(\s+)/)) {
215→    if (/^\s+$/.test(w)) { subtitleText.appendChild(document.createTextNode(' ')); continue; }
216→    const span = document.createElement('span');
217→    span.className = 'word'; span.textContent = w;
218→    span.addEventListener('click', (e) => {
219→      e.stopPropagation();
220→      const clean = cleanWord(w);
221→      if (clean) showWordPopup(clean, e.clientX, e.clientY);
222→    });
223→    subtitleText.appendChild(span);
224→  }
225→}
