244→    row.innerHTML = `<span class="sub-time">${formatTime(s.start)}</span><span class="sub-content">${s.text}</span>`;
245→    row.addEventListener('click', () => {
246→      videoPlayer.currentTime = s.start;
247→      videoPlayer.play();
248→    });
249→    list.appendChild(row);
250→  });
251→}
