const fs = require('fs');
const files = fs.readdirSync('downloads').filter(f => f.endsWith('.vtt'));
console.log('VTT files:', files.length);
if (files[0]) {
  const vtt = fs.readFileSync('downloads/' + files[0], 'utf-8');
